-- {"operators": "OUTER_JOIN,AGGREGATE", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": true, "tables": "ORDER_LINE,NEW_ORDER", "lakeflow": "gold_bikes"}
SELECT ol.OL_W_ID, ol.OL_D_ID, ol.OL_O_ID, COUNT(*) AS line_count, SUM(ol.OL_AMOUNT) AS total_amount, ARG_MIN(ol.OL_I_ID, ol.OL_NUMBER) AS first_item_id, ARG_MAX(ol.OL_I_ID, ol.OL_NUMBER) AS last_item_id, MAX(CASE WHEN no.NO_O_ID IS NOT NULL THEN 1 ELSE 0 END) AS has_new_order FROM ORDER_LINE ol LEFT JOIN NEW_ORDER no ON ol.OL_W_ID = no.NO_W_ID AND ol.OL_D_ID = no.NO_D_ID AND ol.OL_O_ID = no.NO_O_ID GROUP BY ALL
